import{_ as a,o as s,c as e,ag as r,ah as o}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"权限与审批","description":"","frontmatter":{},"headers":[],"relativePath":"features/permissions.md","filePath":"features/permissions.md"}'),d={name:"features/permissions.md"};function l(n,t,i,c,p,h){return s(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="权限与审批" tabindex="-1">权限与审批 <a class="header-anchor" href="#权限与审批" aria-label="Permalink to &quot;权限与审批&quot;">​</a></h1><p>AI 在帮你修改文件、执行命令时，需要你事先授权。这是防止 AI 在无人监督的情况下执行破坏性操作的核心安全机制。本页介绍 LoongCode 的授权模式、对话中的权限请求卡片与计划审批卡片的操作方法。</p><blockquote><p>相关基础：<a href="/docs/guide/quick-start.html">快速上手</a>（执行授权初次介绍）、<a href="/docs/features/conversation.html">对话面板</a>（卡片简述）</p></blockquote><hr><h2 id="为什么需要权限控制" tabindex="-1">为什么需要权限控制 <a class="header-anchor" href="#为什么需要权限控制" aria-label="Permalink to &quot;为什么需要权限控制&quot;">​</a></h2><p>Claude 是一个能够读写文件、执行终端命令、修改代码的 AI Agent。如果不加任何限制，它可能会：</p><ul><li>在你尚未确认时就修改重要文件</li><li>执行你没有预期的终端命令</li><li>连续操作多个步骤而中途无法插手</li></ul><p>LoongCode 通过<strong>执行授权</strong>机制，让你在每次 AI 动手前都有机会看到、批准或拒绝操作，从而保持对工作区的掌控权。</p><hr><h2 id="执行授权模式" tabindex="-1">执行授权模式 <a class="header-anchor" href="#执行授权模式" aria-label="Permalink to &quot;执行授权模式&quot;">​</a></h2><p>在任务选择器条（输入框下方）可以切换<strong>执行授权</strong>档位。Claude CLI 有四个选项，Codex CLI 有三个选项，各自的含义如下。</p><h3 id="claude-cli-—-四种模式" tabindex="-1">Claude CLI — 四种模式 <a class="header-anchor" href="#claude-cli-—-四种模式" aria-label="Permalink to &quot;Claude CLI — 四种模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式（界面原文）</th><th>行为说明</th></tr></thead><tbody><tr><td><strong>default</strong></td><td>每次写文件、执行命令等操作前，均弹出权限请求卡片，等你批准后再执行</td></tr><tr><td><strong>plan</strong></td><td>AI 先输出完整计划，等你在计划审批卡片中批准后再开始执行；批准时还能选择后续改动是否需要逐步确认（详见下文「计划审批卡片」）</td></tr><tr><td><strong>acceptEdits</strong></td><td>文件编辑类操作自动接受，无需每次确认；但 Bash 命令等仍需弹卡片手动批准</td></tr><tr><td><strong>bypassPermissions</strong></td><td>所有操作均自动执行，不弹任何权限卡片</td></tr></tbody></table><p>新手建议：改为 <strong>default</strong> 或 <strong>plan</strong>（出厂默认为 bypassPermissions，即完全自主执行），熟悉 AI 行为后再按需放宽。</p><div class="warning custom-block"><p class="custom-block-title">bypassPermissions 注意事项</p><p><code>bypassPermissions</code> 模式下 AI 会完全自主执行，包括删除文件、运行任意命令。<strong>仅在你完全信任当前任务且工作区内容可随时恢复的情况下使用</strong>，日常开发建议保持 <code>default</code> 或 <code>plan</code>。</p></div><p><strong>如何切换：</strong></p><ol><li>在输入框下方找到选择器条，点击授权模式下拉框（显示当前任务的授权模式）。</li><li>从下拉列表中选择目标模式，立即生效。</li></ol><div class="tip custom-block"><p class="custom-block-title">草稿继承上次设置</p><p>新建任务时，执行授权档位默认继承上一次任务的设置，无需每次重新调整。</p></div><h3 id="codex-cli-—-三种档位" tabindex="-1">Codex CLI — 三种档位 <a class="header-anchor" href="#codex-cli-—-三种档位" aria-label="Permalink to &quot;Codex CLI — 三种档位&quot;">​</a></h3><p>切换到 Codex CLI 后，授权列表变为三个选项：</p><table tabindex="0"><thead><tr><th>档位（界面原文）</th><th>行为说明</th></tr></thead><tbody><tr><td><strong>只读</strong></td><td>AI 只能读取文件，不能写入或执行命令</td></tr><tr><td><strong>自动</strong></td><td>常规操作自动执行（默认档位）</td></tr><tr><td><strong>完全访问</strong></td><td>所有操作均自动执行，等同于 Claude 的 <code>bypassPermissions</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">完全访问注意事项</p><p><strong>完全访问</strong>与 <code>bypassPermissions</code> 行为相同、风险同级——AI 会完全自主执行所有操作。仅在你完全信任当前任务且工作区内容可随时恢复的情况下使用。</p></div><hr><h2 id="对话中的权限请求卡片" tabindex="-1">对话中的权限请求卡片 <a class="header-anchor" href="#对话中的权限请求卡片" aria-label="Permalink to &quot;对话中的权限请求卡片&quot;">​</a></h2><p>在 <code>default</code> 或 <code>acceptEdits</code> 模式下，AI 需要执行写文件、执行命令等操作时，对话区会出现<strong>权限请求</strong>卡片，标题显示「权限请求」。</p><p><img src="'+o+'" alt="截图：对话面板中弹出的权限请求卡片，显示工具名称与操作参数，底部有「允许」「拒绝」按钮，旁边有可折叠的操作详情"></p><h3 id="卡片操作说明" tabindex="-1">卡片操作说明 <a class="header-anchor" href="#卡片操作说明" aria-label="Permalink to &quot;卡片操作说明&quot;">​</a></h3><p><strong>允许</strong>：批准本次操作，AI 继续执行。</p><p><strong>拒绝</strong>：拒绝本次操作，点击后卡片展开一个可选填的文本框，提示「（可选）告诉 Claude 为什么拒绝 / 希望怎么改」，填写完后点击<strong>确认拒绝</strong>，AI 收到拒绝结果后会自行调整方案或向你追问。</p><p>操作步骤（拒绝时）：</p><ol><li>点击<strong>拒绝</strong>，卡片展开理由输入框。</li><li>可选填写拒绝原因（例如：「不要修改这个文件，改另一个」）。</li><li>点击<strong>确认拒绝</strong>使拒绝生效。</li></ol><div class="tip custom-block"><p class="custom-block-title">为什么要两次确认才能拒绝</p><p>二次确认（拒绝 → 确认拒绝）防止误触拒绝，也给你一个填写原因的机会，让 AI 能理解你的意图并重新规划。</p></div><hr><h2 id="计划审批卡片" tabindex="-1">计划审批卡片 <a class="header-anchor" href="#计划审批卡片" aria-label="Permalink to &quot;计划审批卡片&quot;">​</a></h2><p>在 <code>plan</code> 模式下，AI 会先输出一份完整的执行计划，然后停下来等待你审批，此时对话区出现<strong>待批准的计划</strong>卡片。</p><p><img src="'+o+'" alt="截图：对话面板中的待批准计划卡片，显示 Markdown 格式的计划内容，底部显示三个审批按钮"></p><h3 id="三个审批选项" tabindex="-1">三个审批选项 <a class="header-anchor" href="#三个审批选项" aria-label="Permalink to &quot;三个审批选项&quot;">​</a></h3><p><strong>批准·自动接受编辑</strong>：批准计划并立即执行，后续所有文件编辑操作自动确认，无需每步手动批准（相当于以 <code>acceptEdits</code> 模式继续执行）。</p><p><strong>批准·逐步确认</strong>：批准计划并立即执行，但后续每一步的文件改动仍会弹出权限请求卡片，需要你逐一确认（相当于以 <code>default</code> 模式继续执行）。</p><p><strong>拒绝·继续规划</strong>：拒绝当前计划，AI 收到拒绝后会重新规划，生成新的计划供你再次审批。</p><p>操作建议：</p><ul><li>如果计划看起来合理且改动量可控，选<strong>批准·自动接受编辑</strong>，减少后续确认次数。</li><li>如果改动涉及多个关键文件，或你想逐步查看每处修改，选<strong>批准·逐步确认</strong>。</li><li>如果计划方向有误，选<strong>拒绝·继续规划</strong>，并可在输入框补充说明你的意图后等待新计划。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解权限控制机制后，可以前往<a href="/docs/features/browser.html">浏览器标签页</a>了解如何在 LoongCode 内嵌浏览器中浏览网页并将页面内容提供给 AI。</p>',45)])])}const b=a(d,[["render",l]]);export{u as __pageData,b as default};
